import React, { useEffect, useState } from "react";
import axios from "axios";
import { Container, Table, Button, Form } from "react-bootstrap";
import { useAuth } from "../context/AuthContext";

function Medications() {
  const { user } = useAuth();
  const [medications, setMedications] = useState([]);
  const [form, setForm] = useState({ name: "", dosage: "", schedule: "" });

  const fetchMeds = async () => {
    const res = await axios.get(`/api/medications/${user.id}`);
    setMedications(res.data);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    await axios.post("/api/medications", { ...form, user_id: user.id });
    setForm({ name: "", dosage: "", schedule: "" });
    fetchMeds();
  };

  useEffect(() => {
    if (user) fetchMeds();
  }, [user]);

  return (
    <Container className="mt-4">
      <h3>Your Medications</h3>
      <Form onSubmit={handleSubmit} className="my-3">
        <Form.Control
          placeholder="Medication name"
          value={form.name}
          onChange={(e) => setForm({ ...form, name: e.target.value })}
        />
        <Form.Control
          className="mt-2"
          placeholder="Dosage"
          value={form.dosage}
          onChange={(e) => setForm({ ...form, dosage: e.target.value })}
        />
        <Form.Control
          className="mt-2"
          placeholder="Schedule (e.g. Morning & Evening)"
          value={form.schedule}
          onChange={(e) => setForm({ ...form, schedule: e.target.value })}
        />
        <Button type="submit" className="mt-2">Add Medication</Button>
      </Form>

      <Table striped bordered hover>
        <thead>
          <tr>
            <th>Name</th>
            <th>Dosage</th>
            <th>Schedule</th>
          </tr>
        </thead>
        <tbody>
          {medications.map((m) => (
            <tr key={m.id}>
              <td>{m.name}</td>
              <td>{m.dosage}</td>
              <td>{m.schedule}</td>
            </tr>
          ))}
        </tbody>
      </Table>
    </Container>
  );
}

export default Medications;
